mapper.select:
/* com.erns.coching.search.mapper.HwBrandDAO.getList */

SELECT

FROM T_HW_BRAND AA






		ORDER BY AA.SORT_ORD ASC, AA.SEQ ASC




	OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.search.mapper.HwBrandDAO.getListVo */

SELECT

FROM T_HW_BRAND AA






		ORDER BY AA.SORT_ORD ASC, AA.SEQ ASC




	OFFSET #{offset} LIMIT #{rowSize}

    	/* com.erns.coching.search.mapper.HwBrandDAO.load */

		SELECT

		FROM T_HW_BRAND AA

			AND AA.SEQ = #{value, jdbcType=INTEGER}

mapper.insert:
	/* com.erns.coching.search.mapper.HwBrandDAO.insert */

INSERT INTO T_HW_BRAND (
	  SEQ
	, BRAND_FULL_NAME
	, BRAND_KO
	, BRAND_EN
	, COUNT
	, RGT_DTTM
) VALUES (
	  #{seq							, jdbcType=INTEGER}
	, #{brandFullName		, jdbcType=VARCHAR}
	, #{brandKo					, jdbcType=VARCHAR}
	, #{brandEn					, jdbcType=VARCHAR}
	, #{count						, jdbcType=INTEGER}
	, now()			
)

mapper.delete:
/* com.erns.coching.search.mapper.HwBrandDAO.delete */

DELETE FROM T_HW_BRAND

	AND SEQ 	= #{value	, jdbcType=INTEGER}
